import React, { useState } from "react"
import { Link } from "gatsby"

const Sidebar = () => {
  const [openDevops, setOpenDevops] = useState(false)

  return (
    <div style={{ width: "250px", padding: "20px", background: "#f5f5f5" }}>
      
      <h3
        style={{ cursor: "pointer" }}
        onClick={() => setOpenDevops(!openDevops)}
      >
        DevOps ▾
      </h3>

      {openDevops && (
        <ul>
          <li>
            <Link to="/devops/onboarding">Onboarding Steps</Link>
          </li>
        </ul>
      )}

    </div>
  )
}

export default Sidebar